import { client, tasks, batch } from "@trigger.dev/sdk";

// Initialize the Trigger.dev client
client.initialize({
  id: "media-app",
  apiKey: process.env.TRIGGER_API_KEY,
});

// Define types for the pipeline data
interface DownloadInput {
  url: string;
  destination: string;
}

interface DownloadOutput {
  filePath: string;
  size: number;
  duration: number;
}

interface ProcessInput {
  filePath: string;
  operations: string[];
}

interface ProcessOutput {
  processedFilePath: string;
  metadata: Record<string, any>;
}

interface UploadInput {
  filePath: string;
  destinations: string[];
}

interface UploadOutput {
  urls: string[];
  successCount: number;
}

interface MediaPipelineInput {
  trialId: string;
  url: string;
  operations: string[];
  destinations: string[];
}

interface MediaPipelineOutput {
  status: "success" | "failed";
  trialId: string;
  downloadResult?: DownloadOutput;
  processResult?: ProcessOutput;
  uploadResult?: UploadOutput;
  error?: string;
  stepFailed?: string;
}

/**
 * Step 1: Download Task
 * Downloads media from a URL to a specified destination
 */
tasks.define({
  id: "download-task",
  name: "Download Media",
  run: async (payload: DownloadInput) => {
    console.log(`Starting download from ${payload.url} to ${payload.destination}`);

    // Simulate download process
    const startTime = Date.now();

    // In a real implementation, this would use actual download logic
    const downloadResult: DownloadOutput = {
      filePath: `${payload.destination}/media_${Date.now()}.mp4`,
      size: 1024 * 1024 * 50, // 50MB
      duration: Date.now() - startTime,
    };

    console.log(`Download completed: ${downloadResult.filePath}`);
    return downloadResult;
  },
});

/**
 * Step 2: Process Task
 * Processes the downloaded media file with specified operations
 */
tasks.define({
  id: "process-task",
  name: "Process Media",
  run: async (payload: ProcessInput) => {
    console.log(`Starting process for ${payload.filePath} with operations: ${payload.operations.join(", ")}`);

    // Simulate processing
    const startTime = Date.now();

    // In a real implementation, this would use FFmpeg or similar tools
    const processResult: ProcessOutput = {
      processedFilePath: payload.filePath.replace(/\.(\w+)$/, "_processed.$1"),
      metadata: {
        format: "mp4",
        codec: "h264",
        operationsPerformed: payload.operations,
        processingTime: Date.now() - startTime,
      },
    };

    console.log(`Processing completed: ${processResult.processedFilePath}`);
    return processResult;
  },
});

/**
 * Step 3: Upload Task
 * Uploads the processed media to multiple destinations
 * This task can be parallelized using batch.triggerByTaskAndWait
 */
tasks.define({
  id: "upload-task",
  name: "Upload Media",
  run: async (payload: UploadInput) => {
    console.log(`Starting upload of ${payload.filePath} to ${payload.destinations.length} destinations`);

    const uploadResults: string[] = [];

    // In a real implementation, this would upload to S3, CloudFront, CDN, etc.
    for (const destination of payload.destinations) {
      uploadResults.push(`${destination}/media_${Date.now()}.mp4`);
    }

    const result: UploadOutput = {
      urls: uploadResults,
      successCount: uploadResults.length,
    };

    console.log(`Upload completed: ${result.successCount}/${payload.destinations.length} successful`);
    return result;
  },
});

/**
 * Media Pipeline Task
 * Orchestrates the three-step media processing pipeline with error handling
 */
tasks.define({
  id: "media-pipeline-main",
  name: "Media Processing Pipeline",
  run: async (payload: MediaPipelineInput) => {
    const taskIdentifier = `media-pipeline-${payload.trialId}`;
    console.log(`Starting pipeline: ${taskIdentifier}`);

    const result: MediaPipelineOutput = {
      status: "success",
      trialId: payload.trialId,
    };

    try {
      // Step 1: Trigger download-task and wait for result
      console.log(`[${taskIdentifier}] Step 1: Downloading media...`);
      const downloadTask = await tasks.trigger("download-task", {
        url: payload.url,
        destination: `/tmp/trial_${payload.trialId}`,
      });

      const downloadResult = await downloadTask.wait();
      result.downloadResult = downloadResult;
      console.log(`[${taskIdentifier}] Download completed successfully`);

      // Step 2: Trigger process-task with download result and wait
      console.log(`[${taskIdentifier}] Step 2: Processing media...`);
      const processTask = await tasks.trigger("process-task", {
        filePath: downloadResult.filePath,
        operations: payload.operations,
      });

      const processResult = await processTask.wait();
      result.processResult = processResult;
      console.log(`[${taskIdentifier}] Processing completed successfully`);

      // Step 3: Trigger upload-task with process result and wait
      // If uploading to multiple destinations, we could use batch.triggerByTaskAndWait
      // to parallelize the uploads
      console.log(`[${taskIdentifier}] Step 3: Uploading media...`);

      if (payload.destinations.length > 1) {
        // Parallelize uploads using batch.triggerByTaskAndWait
        console.log(`[${taskIdentifier}] Parallelizing uploads to ${payload.destinations.length} destinations...`);

        const uploadTasks = payload.destinations.map((destination) =>
          tasks.trigger("upload-task", {
            filePath: processResult.processedFilePath,
            destinations: [destination],
          })
        );

        const uploadResults = await batch.triggerByTaskAndWait(uploadTasks);

        // Combine results from parallel uploads
        const allUrls: string[] = [];
        let successCount = 0;

        for (const uploadResult of uploadResults) {
          if (uploadResult.success) {
            allUrls.push(...uploadResult.data.urls);
            successCount += uploadResult.data.successCount;
          }
        }

        result.uploadResult = {
          urls: allUrls,
          successCount,
        };
      } else {
        // Single destination, use regular trigger
        const uploadTask = await tasks.trigger("upload-task", {
          filePath: processResult.processedFilePath,
          destinations: payload.destinations,
        });

        const uploadResult = await uploadTask.wait();
        result.uploadResult = uploadResult;
      }

      console.log(`[${taskIdentifier}] Upload completed successfully`);
      console.log(`[${taskIdentifier}] Pipeline completed successfully for trial ${payload.trialId}`);

    } catch (error) {
      // Error handling: Log the error and return failure status
      const errorMessage = error instanceof Error ? error.message : String(error);
      console.error(`[${taskIdentifier}] Pipeline failed:`, errorMessage);

      // Determine which step failed based on which results are present
      if (!result.downloadResult) {
        result.stepFailed = "download";
      } else if (!result.processResult) {
        result.stepFailed = "process";
      } else if (!result.uploadResult) {
        result.stepFailed = "upload";
      }

      result.status = "failed";
      result.error = errorMessage;
    }

    return result;
  },
});

