import { mediaPipelineTask } from "./trigger/media";

/**
 * Example usage of the Media Processing Pipeline
 * 
 * This file demonstrates how to trigger the media pipeline with different configurations
 */

async function runMediaPipelineExample() {
  console.log("=== Media Processing Pipeline Example ===\n");

  // Example 1: Basic pipeline with single destination
  console.log("Example 1: Basic pipeline with single destination");
  const basicPipeline = await tasks.trigger("media-pipeline-main", {
    trialId: "trial-001",
    url: "https://example.com/media/video.mp4",
    operations: ["transcode", "compress", "watermark"],
    destinations: ["s3://bucket/media"],
  });

  const basicResult = await basicPipeline.wait();
  console.log("Basic pipeline result:", basicResult);
  console.log();

  // Example 2: Pipeline with multiple destinations (parallel uploads)
  console.log("Example 2: Pipeline with multiple destinations (parallel uploads)");
  const multiDestPipeline = await tasks.trigger("media-pipeline-main", {
    trialId: "trial-002",
    url: "https://example.com/media/video2.mp4",
    operations: ["transcode", "resize", "optimize"],
    destinations: [
      "s3://us-east-1/media",
      "s3://eu-west-1/media",
      "s3://ap-southeast-1/media",
    ],
  });

  const multiDestResult = await multiDestPipeline.wait();
  console.log("Multi-destination pipeline result:", multiDestResult);
  console.log();

  // Example 3: Pipeline with error handling demonstration
  console.log("Example 3: Pipeline with invalid URL (error handling demo)");
  const errorPipeline = await tasks.trigger("media-pipeline-main", {
    trialId: "trial-003",
    url: "https://invalid-url.example.com/media.mp4",
    operations: ["transcode"],
    destinations: ["s3://bucket/media"],
  });

  const errorResult = await errorPipeline.wait();
  console.log("Error pipeline result:", errorResult);
  console.log();
}

// Run the example if this file is executed directly
if (require.main === module) {
  runMediaPipelineExample()
    .then(() => {
      console.log("Examples completed successfully");
      process.exit(0);
    })
    .catch((error) => {
      console.error("Error running examples:", error);
      process.exit(1);
    });
}

export { runMediaPipelineExample };

